sp_widget.client_script:
api.controller = function ($scope, scmFlyover, scmBreadcrumbsManager) {
    const c = this;

    c.openFlyover = function () {
        const flyover = new scmFlyover("flyover-example", $scope);
        flyover.setTitle("Example flyover");
        flyover.setSubTitle("This is an example subtitle");
        flyover.setTransactionId(c.data.transactionId);
        flyover.open();
    };

    scmBreadcrumbsManager.set(c.data.breadcrumbs);
};

sp_widget.css:
.card__body {
    display: flex;
    flex-direction: row;
    justify-content: space-between;

    .card-content {
        display: flex;
        flex-direction: column;
    }
}

sp_widget.script:
(function () {
    function generateTestData() {
        const nodes = [];

        const colors = [
            "navy",
            "blue",
            "purple",
            "turquoise",
            "apple",
            "petrol",
            "iris",
            "pink",
            "red",
            "orange",
        ];

        let nodeId = 1;

        for (let root = 1; root <= 2; root++) {
            nodes.push({
                id: String(nodeId++),
                title: `Root Node ${root}`,
                parent: null,
                color: colors[root % colors.length],
                template: "scm-tree-card",
            });
            const rootId = String(nodeId - 1);

            const level1Count = 0 + Math.floor(Math.random() * 5);
            for (let l1 = 1; l1 <= level1Count; l1++) {
                nodes.push({
                    id: String(nodeId++),
                    title: `Node ${root}.${l1}`,
                    parent: rootId,
                    color: colors[(root + l1) % colors.length],
                    template: "scm-tree-card",
                });
                const level1Id = String(nodeId - 1);

                if (Math.random() < 0.6) {
                    const level2Count = 7 + Math.floor(Math.random() * 6);
                    for (let l2 = 1; l2 <= level2Count; l2++) {
                        nodes.push({
                            id: String(nodeId++),
                            title: `Node ${root}.${l1}.${l2}`,
                            parent: level1Id,
                            color: colors[(root + l1 + l2) % colors.length],
                            template: "scm-tree-card",
                        });
                        const level2Id = String(nodeId - 1);

                        if (Math.random() < 0.4) {
                            const level3Count =
                                2 + Math.floor(Math.random() * 4);
                            for (let l3 = 1; l3 <= level3Count; l3++) {
                                nodes.push({
                                    id: String(nodeId++),
                                    title: `Node ${root}.${l1}.${l2}.${l3}`,
                                    parent: level2Id,
                                    color: colors[
                                        (root + l1 + l2 + l3) % colors.length
                                    ],
                                    template: "scm-tree-card",
                                    callbacks: {
                                        viewAction: "openFlyover",
                                    },
                                });
                                const level3Id = String(nodeId - 1);

                                if (Math.random() < 0.2) {
                                    const level4Count =
                                        1 + Math.floor(Math.random() * 3);
                                    for (let l4 = 1; l4 <= level4Count; l4++) {
                                        nodes.push({
                                            id: String(nodeId++),
                                            title: `Node ${root}.${l1}.${l2}.${l3}.${l4}`,
                                            parent: level3Id,
                                            color: colors[
                                                (root + l1 + l2 + l3 + l4) %
                                                    colors.length
                                            ],
                                            template: "scm-tree-card",
                                        });
                                    }
                                }
                            }
                        }
                    }
                }
            }
        }

        return nodes;
    }

    const transactionId = input?.transactionId || gs.generateGUID();
    data.transactionId = transactionId;

    const logger = new Logger({
        transactionId: transactionId,
        source: "contract-tree.server.js",
        includeTimeStamp: true,
        includeUserInfo: true,
        includeSessionId: true,
    });

    const nodes = generateTestData();
    data.treeWidget = $sp.getWidget("scm-tree", {
        nodes: nodes,
        transactionId: transactionId,
        availableCallbacks: {
            openFlyover: "parent.openFlyover",
        },
    });

    data.breadcrumbs = [
        ...Constants.HOME_BREADCRUMB,
        { title: "Contracts tree", link: "?id=contract_tree" },
    ];
})();
